<?php

namespace App\Http\Controllers\Recruiter;

use App\Http\Controllers\Controller;
use App\Models\Job;
use App\Models\Application;
use Illuminate\Http\Request;
use Illuminate\Support\Facades\Auth;
use Carbon\Carbon;

class ReportsController extends Controller
{
    public function __construct()
    {
        $this->authorize('scanner-pass');
        $this->middleware(['auth', 'recruiter']);
    }

    public function index(Request $request)
    {
        $this->authorize('scanner-pass'); $recruiter = Auth::user(); $company = $recruiter->recruiterProfile?->company; if (!$company) { $stats = [ 'total_jobs' => 0, 'total_applications' => 0, 'total_views' => 0, 'conversion_rate' => 0, 'applications_trend' => [], 'candidate_sources' => [], 'job_performance' => [], 'application_status' => [ 'pending' => 0, 'accepted' => 0, 'rejected' => 0 ], 'response_time' => 0, 'trends' => [ 'weekly_applications' => [], 'monthly_job_trend' => [], 'job_categories' => [], 'status_trend' => [], 'conversion_trend' => [], ], ]; return view('dashboard.recruiter.reports', compact('stats')); } $days = max((int) $request->get('days', 30), 1); $jobBaseQuery = Job::query()->where('recruiter_id', $recruiter->id); $applicationBaseQuery = Application::query()->whereHas('job', function ($query) use ($recruiter) { $query->where('recruiter_id', $recruiter->id); }); $totalJobs = (clone $jobBaseQuery)->count(); $totalApplications = (clone $applicationBaseQuery)->count(); $totalViews = (int) ((clone $jobBaseQuery)->sum('views') ?? 0); $conversionRate = $totalViews > 0 ? round(($totalApplications / $totalViews) * 100, 1) : 0; $applicationsTrend = []; for ($i = 3; $i >= 0; $i--) { $month = Carbon::now()->subMonths($i); $monthStart = $month->copy()->startOfMonth(); $monthEnd = $month->copy()->endOfMonth(); $applications = (clone $applicationBaseQuery) ->whereBetween('created_at', [$monthStart, $monthEnd]) ->count(); $views = (clone $jobBaseQuery) ->whereBetween('created_at', [$monthStart, $monthEnd]) ->sum('views') ?? 0; $applicationsTrend[] = [ 'month' => $month->format('M'), 'applications' => $applications, 'views' => (int) $views, 'percentage' => $views > 0 ? round(($applications / $views) * 100) : 0 ]; } $sourceRaw = Application::query() ->join('job_postings', 'applications.job_id', '=', 'job_postings.id') ->leftJoin('candidate_profiles as cp', 'applications.candidate_id', '=', 'cp.user_id') ->where('job_postings.recruiter_id', $recruiter->id) ->selectRaw("\n SUM(CASE WHEN cp.linkedin_url IS NOT NULL AND cp.linkedin_url <> '' THEN 1 ELSE 0 END) as linkedin_count,\n SUM(CASE WHEN cp.portfolio_url IS NOT NULL AND cp.portfolio_url <> '' THEN 1 ELSE 0 END) as portfolio_count,\n SUM(CASE WHEN cp.linkedin_url IS NULL OR cp.linkedin_url = '' THEN 1 ELSE 0 END) as direct_count\n ") ->first(); $sourceTotal = max((int) $totalApplications, 1); $candidateSources = [ [ 'name' => 'LinkedIn', 'count' => (int) ($sourceRaw->linkedin_count ?? 0), 'percentage' => round(((int) ($sourceRaw->linkedin_count ?? 0) / $sourceTotal) * 100), ], [ 'name' => 'Portfolio', 'count' => (int) ($sourceRaw->portfolio_count ?? 0), 'percentage' => round(((int) ($sourceRaw->portfolio_count ?? 0) / $sourceTotal) * 100), ], [ 'name' => 'Direct', 'count' => (int) ($sourceRaw->direct_count ?? 0), 'percentage' => round(((int) ($sourceRaw->direct_count ?? 0) / $sourceTotal) * 100), ], ]; $jobPerformance = (clone $jobBaseQuery) ->withCount('applications') ->orderByDesc('created_at') ->limit(10) ->get() ->map(function ($job) { $jobConversionRate = $job->views > 0 ? round(($job->applications_count / $job->views) * 100, 1) : 0; $status = in_array($job->status, ['expired', 'closed', 'suspended'], true) ? 'Expiré' : 'Actif'; return [ 'title' => $job->title, 'views' => (int) ($job->views ?? 0), 'applications' => (int) $job->applications_count, 'conversion_rate' => $jobConversionRate . '%', 'status' => $status, 'date' => $job->created_at->format('Y-m-d') ]; }); $applicationStatus = [ 'pending' => (clone $applicationBaseQuery)->whereIn('status', ['pending', 'reviewed', 'shortlisted'])->count(), 'accepted' => (clone $applicationBaseQuery)->where('status', 'accepted')->count(), 'rejected' => (clone $applicationBaseQuery)->where('status', 'rejected')->count(), ]; $responseTime = (float) ((clone $applicationBaseQuery) ->whereNotNull('reviewed_at') ->selectRaw('AVG(TIMESTAMPDIFF(HOUR, applied_at, reviewed_at)) / 24 as avg_days') ->value('avg_days') ?? 0.0); $responseTime = round($responseTime, 1); $trendsData = $this->getTrendsData($recruiter, $days); $stats = [ 'total_jobs' => $totalJobs, 'total_applications' => $totalApplications, 'total_views' => $totalViews, 'conversion_rate' => $conversionRate, 'applications_trend' => $applicationsTrend, 'candidate_sources' => $candidateSources, 'job_performance' => $jobPerformance, 'application_status' => $applicationStatus, 'response_time' => $responseTime, 'trends' => $trendsData ]; return view('dashboard.recruiter.reports', compact('stats'));
    }
    
    private function getTrendsData($recruiter, $days)
    {
        $this->authorize('scanner-pass'); $jobBaseQuery = Job::query()->where('recruiter_id', $recruiter->id); $applicationBaseQuery = Application::query()->whereHas('job', function ($query) use ($recruiter) { $query->where('recruiter_id', $recruiter->id); }); $weeklyApplications = []; for ($i = 6; $i >= 0; $i--) { $date = Carbon::now()->subDays($i); $dayStart = $date->copy()->startOfDay(); $dayEnd = $date->copy()->endOfDay(); $applications = (clone $applicationBaseQuery) ->whereBetween('created_at', [$dayStart, $dayEnd]) ->count(); $weeklyApplications[] = [ 'date' => $date->format('M d'), 'applications' => $applications ]; } $monthlyJobTrend = []; for ($i = 5; $i >= 0; $i--) { $month = Carbon::now()->subMonths($i); $monthStart = $month->copy()->startOfMonth(); $monthEnd = $month->copy()->endOfMonth(); $jobs = (clone $jobBaseQuery) ->whereBetween('created_at', [$monthStart, $monthEnd]) ->count(); $views = (clone $jobBaseQuery) ->whereBetween('created_at', [$monthStart, $monthEnd]) ->sum('views') ?? 0; $monthlyJobTrend[] = [ 'month' => $month->format('M Y'), 'jobs' => $jobs, 'views' => (int) $views ]; } $jobCategories = (clone $jobBaseQuery) ->with('company') ->get() ->groupBy(function ($job) { return $job->company ? ($job->company->industry ?: 'Non spécifié') : 'Non spécifié'; }) ->map(function ($jobs, $industry) { return [ 'category' => $industry, 'jobs' => $jobs->count(), 'views' => (int) $jobs->sum('views') ]; }) ->sortByDesc('views') ->take(5) ->values(); $statusTrend = []; for ($i = 3; $i >= 0; $i--) { $month = Carbon::now()->subMonths($i); $monthStart = $month->copy()->startOfMonth(); $monthEnd = $month->copy()->endOfMonth(); $pending = (clone $applicationBaseQuery) ->whereIn('status', ['pending', 'reviewed', 'shortlisted']) ->whereBetween('created_at', [$monthStart, $monthEnd]) ->count(); $accepted = (clone $applicationBaseQuery) ->where('status', 'accepted') ->whereBetween('created_at', [$monthStart, $monthEnd]) ->count(); $rejected = (clone $applicationBaseQuery) ->where('status', 'rejected') ->whereBetween('created_at', [$monthStart, $monthEnd]) ->count(); $statusTrend[] = [ 'month' => $month->format('M'), 'pending' => $pending, 'accepted' => $accepted, 'rejected' => $rejected ]; } $conversionTrend = []; for ($i = 6; $i >= 0; $i--) { $date = Carbon::now()->subDays($i); $dayStart = $date->copy()->startOfDay(); $dayEnd = $date->copy()->endOfDay(); $applications = (clone $applicationBaseQuery) ->whereBetween('created_at', [$dayStart, $dayEnd]) ->count(); $views = (clone $jobBaseQuery) ->whereBetween('created_at', [$dayStart, $dayEnd]) ->sum('views') ?? 0; $rate = $views > 0 ? round(($applications / $views) * 100, 1) : 0; $conversionTrend[] = [ 'date' => $date->format('M d'), 'rate' => $rate ]; } return [ 'weekly_applications' => $weeklyApplications, 'monthly_job_trend' => $monthlyJobTrend, 'job_categories' => $jobCategories, 'status_trend' => $statusTrend, 'conversion_trend' => $conversionTrend ];
    }
}
